//
//  AppView.swift
//  Radiacode
//
//  Created by Pavel Marinchenko on 19.02.2023.
//

import SwiftUI
import GoogleMaps
import FactoryKit
import Siren

@main
struct AppView: SwiftUI.App {

    @InjectedObservable(\.migration) private var migration
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    @Injected(\.databaseMigrationManager) private var databaseMigrationManager

    var body: some Scene {
        WindowGroup {
            Group {
                switch migration.state {
                case .launching:
                    LaunchScreen()
                case .migrating:
                    MigrationView()
                case .failure(let databaseURL):
                    MigrationErrorView(databaseURL: databaseURL)
                case .ready:
                    MainContentView()
                }
            }
            .animation(.easeInOut(duration: 0.3), value: migration.state)
            .onAppear {
                guard UIApplication.shared.isProtectedDataAvailable else { return }
                prepareDatabase()
            }
            .onReceive(NotificationCenter.default.publisher(for: UIApplication.protectedDataDidBecomeAvailableNotification)) { _ in
                prepareDatabase()
            }
        }
    }

    private func prepareDatabase() {
        guard migration.state == .launching else { return }
        _ = Container.shared.backgroundDatabase()
        Task {
            await databaseMigrationManager.migrateDatabaseIfNeeded()
        }
    }
}

final class AppDelegate: NSObject, UIApplicationDelegate {

    @Injected(\.analyticsEngine) private var analyticsEngine

    func application(
        _ application: UIApplication,
        didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]? = nil
    ) -> Bool {

        GMSServices.provideAPIKey("AIzaSyAFeEWdEANjG6T7w-VZhsgsCBEo2vASlyw")
        analyticsEngine.reportEvent(LifecycleEvent.launched)
        UIView.appearance(whenContainedInInstancesOf: [UIAlertController.self]).tintColor = UIColor(.accentBlue)
        UISearchBar.appearance().tintColor = UIColor(.accentBlue)
        UITabBar.appearance().isTranslucent = false

        Siren.shared.wail(performCheck: .onDemand)

        return true
    }
}

