//
//  BackupManifest.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 19.08.2025.
//

import Foundation
import FactoryKit
import SwiftData

extension Container {

    var backupCoordinator: Factory<BackupCoordinator> {
        self { BackupCoordinator() }
    }
}

final class BackupCoordinator {

    @LazyInjected(\.databaseContainerProvider) private var databaseContainerProvider
    @LazyInjected(\.backupExportManager) private var backupExportManager
    @LazyInjected(\.backupImportManager) private var backupImportManager

    @LazyInjected(\.backgroundDatabase) private var backgroundDatabase
    @LazyInjected(\.spectrumFolderRepository) private var spectrumFolderRepository

    func storeFromDatabase(from databaseUrl: URL) async -> Bool {
        do {
            let container = try databaseContainerProvider.container(for: databaseUrl)
            // Попытка выгрузить данные базы в json файлы
            if let models = DatabaseMigrationPlan.schemas
                .first(where: { $0.versionIdentifier == container.schema.version })?
                .migratableModels {
                // Параллелим по моделям; для безопасности создаём отдельный ModelContext на задачу
                try await withThrowingTaskGroup(of: Void.self) { group in
                    for model in models {
                        group.addTask {
                            let context = ModelContext(container)
                            try self.backupExportManager.export(model, from: context)
                        }
                    }
                    try await group.waitForAll()
                }
            }
            return true
        } catch {
            Log.error(error)
            return false
        }
    }

    func restore() async {
        guard let models = DatabaseMigrationPlan.schemas.last?.migratableModels else { return }
        for model in models {
            do {
                try await backupImportManager.importModel(model)
            } catch {
                Log.error(error)
            }
        }
    }

    func clearAllObjectsDB() async throws {
        // Костыль изза бага с удалением nullify зависимости parentFolder
        await spectrumFolderRepository.removeFolder(SpectrumMainLibraryUseCaseImpl.Consts.mainFolderId)
        guard let models = DatabaseMigrationPlan.schemas.last?.models else { return }
        // Еще один Костыль, в проде обычное удаление не работает, в виду того что не удается разрезолвить тип для удаления (изза generic)
        try await backgroundDatabase.withModelContext { context in
            for type in models {
                try self.erase(type, context: context)
            }
            try context.save()
        }
    }

    private func erase<T: PersistentModel>(_ type: T.Type, context: ModelContext) throws {
        try context.delete(model: type)
    }
}

