5	//  Created by Matvey Kozin on 14.08.2025.
6	//
7	
8	import Foundation
9	import ZIPFoundation
10	import FactoryKit
11	
12	extension Container {
13	    
14	    var databaseBackupFileManager: Factory<DatabaseBackupFileManager> {
15	        self { DatabaseBackupFileManagerImpl() }.shared
16	    }
17	}
18	
19	enum DatabaseBackupTarget {
20	    case `import`
21	    case backup
22	    case zip
23	}
24	
25	protocol DatabaseBackupFileManager {
26	    func backupAndResetMainDatabase() throws
27	    func brokenDatabase() -> URL?
28	    
29	    func zipDB() throws -> URL
30	        
31	    func removeModel(_ url: URL) throws
32	    func removeDatabase(database: DatabaseBackupTarget) throws
33	    
34	    func exportMainDB() throws -> URL
35	    func importDatabase(from url: URL) throws -> URL
36	    
37	    func modelURL(for modelName: String) throws -> URL
38	}
39	
40	final class DatabaseBackupFileManagerImpl: DatabaseBackupFileManager {
41	        
42	    private enum BackupFileManagerError: Error {
43	        case backupFolderNotCreated
44	        case importFailed
45	    }
46	    
47	    private enum Consts {
48	        static let fileManager = FileManager.default
49	        static let applicationSupportDirectory = URL.applicationSupportDirectory
50	        static let temporaryDirectory = URL.temporaryDirectory
51	
52	        static let targetFiles = [
53	            "default.store",
54	            "default.store-wal",
55	            "default.store-shm"
56	        ]
57	
58	        static let backupFolderName = "Backup"
59	        static let databaseFolderName = "Database"
60	        static let modelsFolderName = "Models"
61	        static let backupFileName = "radiacode_backup.zip"
62	
63	        static let importFolderName = "Import"
64	        static let exportFolderName = "Export"
65	        static let exportDatabaseFileName = "radiacode_database.zip"
66	    }
67	    
68	    private lazy var backupFolder: URL? = {
69	        do {
70	            let backupDirectory = Consts.applicationSupportDirectory.appendingPathComponent(Consts.backupFolderName)
71	            if !Consts.fileManager.fileExists(atPath: backupDirectory.path) {
72	                try Consts.fileManager.createDirectory(at: backupDirectory, withIntermediateDirectories: true, attributes: nil)
73	            }
74	            return backupDirectory
75	        } catch {
76	            Log.error(error)
77	            return nil
78	        }
79	    }()
80	    
81	    private var databaseFolder: URL? {
82	        guard let backupFolder else { return nil }
83	        return backupFolder.appendingPathComponent(Consts.databaseFolderName)
84	    }
85	    
86	    private var modelsFolder: URL? {
87	        guard let backupFolder else { return nil }
88	        return backupFolder.appendingPathComponent(Consts.modelsFolderName)
89	    }
90	
91	    func backupAndResetMainDatabase() throws {
92	        guard let databaseFolder else {
93	            throw BackupFileManagerError.backupFolderNotCreated
94	        }
95	        
96	        if !Consts.fileManager.fileExists(atPath: databaseFolder.path) {
97	            try Consts.fileManager.createDirectory(at: databaseFolder, withIntermediateDirectories: true, attributes: nil)
98	        }
99	        
100	        for fileName in Consts.targetFiles {
101	            let sourceURL = Consts.applicationSupportDirectory.appendingPathComponent(fileName)
102	            guard Consts.fileManager.fileExists(atPath: sourceURL.path) else { continue }
103	            let destURL = databaseFolder.appendingPathComponent(fileName)
104	            try removeIfExists(destURL)
105	            try Consts.fileManager.copyItem(at: sourceURL, to: destURL)
106	            try removeIfExists(sourceURL)
107	        }
108	    }
109	    
110	    func brokenDatabase() -> URL? {
111	        guard let databaseFolder else { return nil }
112	        let storeURL = databaseFolder.appendingPathComponent(Consts.targetFiles[0])
113	        if Consts.fileManager.fileExists(atPath: storeURL.path) {
114	            return storeURL
115	        } else {
116	            return nil
117	        }
118	    }
119	    
120	    func zipDB() throws -> URL {
121	        guard let backupFolder, let databaseFolder else {
122	            throw BackupFileManagerError.backupFolderNotCreated
123	        }
124	        let archiveURL = backupFolder.appendingPathComponent(Consts.backupFileName)
125	        if !Consts.fileManager.fileExists(atPath: archiveURL.path) {
126	            try Consts.fileManager.zipItem(at: databaseFolder, to: archiveURL, shouldKeepParent: false)
127	        }
128	        return archiveURL
129	    }
130	    
131	    func removeDatabase(database: DatabaseBackupTarget) throws {
132	        let urlToDelete: URL
133	        switch database {
134	        case .backup:
135	            guard let databaseFolder else {
136	                throw BackupFileManagerError.backupFolderNotCreated
137	            }
138	            urlToDelete = databaseFolder
139	        case .import:
140	            urlToDelete = Consts.temporaryDirectory.appendingPathComponent(Consts.importFolderName)
141	        case .zip:
142	            guard let backupFolder else {
143	                throw BackupFileManagerError.backupFolderNotCreated
144	            }
145	            urlToDelete = backupFolder.appendingPathComponent(Consts.backupFileName)
146	        }
147	        try removeIfExists(urlToDelete)
148	    }
149	
150	    func removeModel(_ url: URL) throws {
151	        try removeIfExists(url)
152	    }
153	    
154	    func exportMainDB() throws -> URL {
155	        let exportFolder = try createNewFolder(Consts.exportFolderName)
156	        let exportDatabaseFolder = try createNewFolder(Consts.databaseFolderName, directory: exportFolder)
157	
158	        for fileName in Consts.targetFiles {
159	            let sourceURL = Consts.applicationSupportDirectory.appendingPathComponent(fileName)
160	            if Consts.fileManager.fileExists(atPath: sourceURL.path) {
161	                let destURL = exportDatabaseFolder.appendingPathComponent(fileName)
162	                try Consts.fileManager.copyItem(at: sourceURL, to: destURL)
163	            }
164	        }
165	        
166	        let archiveURL = exportFolder.appendingPathComponent(Consts.exportDatabaseFileName)
167	        try removeIfExists(archiveURL)
168	        try Consts.fileManager.zipItem(at: exportDatabaseFolder, to: archiveURL, shouldKeepParent: false)
169	        try removeIfExists(exportDatabaseFolder)
170	        return archiveURL
171	    }
172	    
173	    func importDatabase(from url: URL) throws -> URL {
174	        let importFolder = try createNewFolder(Consts.importFolderName)
175	        try Consts.fileManager.unzipItem(at: url, to: importFolder)
176	        let storeURL = importFolder.appendingPathComponent(Consts.targetFiles[0])
177	        if Consts.fileManager.fileExists(atPath: storeURL.path) {
178	            return storeURL
179	        } else {
180	            throw BackupFileManagerError.importFailed
181	        }
182	    }
183	    
184	    private func createNewFolder(_ folderName: String, directory: URL = Consts.temporaryDirectory) throws -> URL {
185	        let folder = directory.appendingPathComponent(folderName)
186	        try removeIfExists(folder)
187	        try Consts.fileManager.createDirectory(at: folder, withIntermediateDirectories: true, attributes: nil)
188	        return folder
189	    }
190	
191	    func modelURL(for modelName: String) throws -> URL {
192	        guard let modelsFolder else {
193	            throw BackupFileManagerError.backupFolderNotCreated
194	        }
195	        if !Consts.fileManager.fileExists(atPath: modelsFolder.path) {
196	            try Consts.fileManager.createDirectory(at: modelsFolder, withIntermediateDirectories: true, attributes: nil)
197	        }
198	        
199	        return modelsFolder.appendingPathComponent("\(modelName).json")
200	    }
201	    
202	    private func removeIfExists(_ url: URL) throws {
203	        if Consts.fileManager.fileExists(atPath: url.path) {
204	            try Consts.fileManager.removeItem(at: url)
205	        }
206	    }
207	}
