import Foundation
import SwiftData
import FactoryKit

extension Container {
    var backupExportManager: Factory<BackupExporting> {
        self { BackupExportManager() }
    }
}

protocol BackupExporting {
    func export<T: MigratablePersistentModel>(_ type: T.Type, from context: ModelContext) throws
}

final class BackupExportManager: BackupExporting {

    @LazyInjected(\.databaseBackupFileManager) private var databaseBackupFileManager

    func export<T: MigratablePersistentModel>(_ type: T.Type, from context: ModelContext) throws {
        let modelName = T.BackupModel.typeId
        let url = try databaseBackupFileManager.modelURL(for: modelName)

        let writer = JSONWriter(url: url)
        defer { writer.close() }

        var descriptor = FetchDescriptor<T>()
        try descriptor.stream(in: context) { _, batch in
            for object in batch {
                do {
                    let payload = try object.asMigrated()
                    try writer.append(payload)
                } catch {
                    Log.error(error)
                }
            }
            try writer.flush()
        }
        try context.delete(model: T.self)
        try context.save()
    }
}

