//
//  BackupImportManager.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 26.08.2025.
//

import Foundation
import SwiftData
import FactoryKit

extension Container {
    var backupImportManager: Factory<BackupImporting> {
        self { BackupImportManager() }
    }
}

protocol BackupImporting {
    func importModel<T: MigratableModel>(_ type: T.Type) async throws
}

final class BackupImportManager: BackupImporting {

    @LazyInjected(\.databaseBackupFileManager) private var databaseBackupFileManager
    @LazyInjected(\.backgroundDatabase) private var backgroundDatabase

    func importModel<T: MigratableModel>(_ type: T.Type) async throws {
        let modelName = T.BackupModel.typeId
        let url = try databaseBackupFileManager.modelURL(for: modelName)
        guard FileManager.default.fileExists(atPath: url.path) else { return }

        let reader = try JSONReader<T.BackupModel>(url: url)
        defer { reader.close() }

        try await backgroundDatabase.withModelContext { context in
            var inserted = 0
            for item in reader {
                try autoreleasepool {
                    _ = try? item.insert(in: context)
                    inserted += 1
                    if inserted % DatabaseConstants.batchSize == 0 {
                        try context.save()
                    }
                }
            }
            try context.save()
        }
        try databaseBackupFileManager.removeModel(url)
    }
}

