//
//  JSONReader.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 29.08.2025.
//

import Foundation

final class JSONReader<T: Decodable>: Sequence, IteratorProtocol {

    private lazy var decoder: JSONDecoder = {
        let decoder = JSONDecoder()
        return decoder
    }()

    private let fileHandle: FileHandle
    private var buffer: Data
    private let chunkSize: Int = 1024 * 1024 // 1 MB буфер
    private let maxLineSize: Int = 10 * 1024 * 1024 // Максимальный размер строки (10 MB)
    private var isEOF: Bool = false

    init(url: URL) throws {
        self.fileHandle = try FileHandle(forReadingFrom: url)
        self.buffer = Data(capacity: chunkSize) // Инициализируем буфер с начальной ёмкостью
    }

    func next() -> T? {
        var currentLine = Data()

        while !isEOF {
            // Если буфер пуст, читаем новый кусок данных
            if buffer.isEmpty {
                do {
                    if let chunk = try fileHandle.read(upToCount: chunkSize), !chunk.isEmpty {
                        buffer.append(chunk)
                    } else {
                        isEOF = true
                        // Если есть накопленные данные, пытаемся декодировать
                        if !currentLine.isEmpty {
                            return try? decodeLine(currentLine)
                        }
                        return nil
                    }
                } catch {
                    Log.error(error)
                    return nil
                }
            }

            // Ищем разделитель в буфере
            if let range = buffer.range(of: JSONWriter.Consts.delimiter) {
                // Добавляем данные до разделителя в currentLine
                let lineData = buffer.subdata(in: 0..<range.lowerBound)

                // Проверяем, не превышает ли размер строки допустимый лимит
                guard currentLine.count + lineData.count <= maxLineSize else {
                    Log.error("Line size exceeds limit of \(maxLineSize) bytes")
                    buffer = Data() // Очищаем буфер
                    return nil // Пропускаем слишком большую строку
                }

                currentLine.append(lineData)
                // Удаляем обработанные данные и разделитель из буфера
                buffer = buffer.subdata(in: range.upperBound..<buffer.count)

                // Пытаемся декодировать строку
                if let result = try? decodeLine(currentLine) {
                    return result
                }
                currentLine = Data() // Очищаем, если декодирование не удалось
            } else {
                // Проверяем, не превышает ли размер строки допустимый лимит
                guard currentLine.count + buffer.count <= maxLineSize else {
                    Log.error("Line size exceeds limit of \(maxLineSize) bytes")
                    buffer = Data() // Очищаем буфер
                    return nil // Пропускаем слишком большую строку
                }

                // Переносим данные из буфера в currentLine
                currentLine.append(buffer)
                buffer = Data()
            }
        }

        // Если достигнут конец файла и есть накопленные данные
        if !currentLine.isEmpty {
            return try? decodeLine(currentLine)
        }

        return nil
    }

    private func decodeLine(_ data: Data) throws -> T? {
        guard !data.isEmpty else { return nil }
        do {
            return try decoder.decode(T.self, from: data)
        } catch {
            Log.error(error)
            throw error
        }
    }

    func close() {
        do {
            try fileHandle.close()
        } catch {
            Log.error(error)
        }
        buffer = Data() // Очищаем буфер
    }

    func makeIterator() -> some IteratorProtocol {
        self
    }
}

