25	        self.url = url
26	    }
27	    
28	    private func openIfNeededForAppend() throws {
29	        guard handle == nil else { return }
30	
31	        // Логика «перезаписать при первой записи»
32	        if FileManager.default.fileExists(atPath: url.path) {
33	            try? FileManager.default.removeItem(at: url)
34	        }
35	
36	        // Cоздаём пустой файл перед первой записью
37	        if !FileManager.default.fileExists(atPath: url.path) {
38	            FileManager.default.createFile(atPath: url.path, contents: nil)
39	        }
40	        let handle = try FileHandle(forWritingTo: url)
41	
42	        self.handle = handle
