//
//  JSONStore.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 26.08.2025.
//

import Foundation

final class JSONWriter {

    enum Consts {
        static let delimiter: Data = Data([0x0A])
    }

    private let url: URL
    private var handle: FileHandle?

    private lazy var encoder: JSONEncoder = {
        let e = JSONEncoder()
        return e
    }()

    init(url: URL) {
        self.url = url
    }

    private func openIfNeededForAppend() throws {
        guard handle == nil else { return }

        // Логика «перезаписать при первой записи»
        if FileManager.default.fileExists(atPath: url.path) {
            try? FileManager.default.removeItem(at: url)
        }

        // Cоздаём пустой файл перед первой записью
        if !FileManager.default.fileExists(atPath: url.path) {
            FileManager.default.createFile(atPath: url.path, contents: nil)
        }
        let handle = try FileHandle(forWritingTo: url)

        self.handle = handle
    }

    func append<T: Encodable>(_ item: T) throws {
        let data = try encoder.encode(item)
        try openIfNeededForAppend()
        guard let handle else { return }
        try handle.write(contentsOf: data)
        try handle.write(contentsOf: Consts.delimiter) // '\n'
    }

    /// Принудительно сбросить буфер на диск
    func flush() throws {
        guard let handle else { return }
        try handle.synchronize()
    }

    /// Закрыть файл
    func close() {
        if let handle {
            do {
                try handle.close()
            } catch {
                Log.error(error)
            }
            self.handle = nil
        }
    }
}

