import Foundation
import SwiftData

struct TrackMigration: Codable, BackupRestorableModel {

    let identifier: String
    let title: String
    let devices: Set<String>
    let startDate: Date
    let importDate: Date?
    let isFinished: Bool
    let lastUpdate: Int?
    let peakCountRate: Float?
    let peakDoseRate: Float?
    let comment: String?
    let periods: [Period]
    let markers: [MarkerMigration]

    func insert(in context: ModelContext) -> TrackObject {
        if !markers.isEmpty {
            var insertedCount = 0
            for marker in markers {
                marker.insert(in: context)
                insertedCount += 1

                if insertedCount % DatabaseConstants.batchSize == 0 {
                    do {
                        try context.save()
                    } catch {
                        Log.error(error)
                    }
                }
            }
        }

        let periods = periods.map { $0.insert(in: context) }
        let trackObject = TrackObject(
            id: identifier,
            title: title,
            devices: devices,
            startDate: startDate,
            importDate: importDate,
            isFinished: isFinished,
            lastUpdate: lastUpdate,
            comment: comment
        )
        trackObject.peakCountRate = peakCountRate
        trackObject.peakDoseRate = peakDoseRate
        trackObject.timePeriod = periods

        context.insert(trackObject)
        return trackObject
    }
}

