import SwiftData

struct StreamProgress {
    let totalCount: Int
    let processedCount: Int
}

extension FetchDescriptor where T: PersistentModel {
    mutating func stream(
        in context: ModelContext,
        batchSize: Int = DatabaseConstants.batchSize,
        onBatch: (_ progress: StreamProgress, _ batch: [T]) throws -> Void
    ) throws {
        let total = try context.fetchCount(self)
        guard total > 0 else { return }
        self.fetchLimit = batchSize
        var offset = 0

        while offset < total {
            self.fetchOffset = offset
            let batch = try context.fetch(self)
            if batch.isEmpty { break }
            let processed = min(offset + batch.count, total)
            try onBatch(StreamProgress(totalCount: total, processedCount: processed), batch)
            offset += batch.count
        }
    }
}

