//
//  Database+Dependency.swift
//  Radiacode
//
//  Created by Matvey Kozin on 06.06.2024.
//

import Foundation
import FactoryKit
import SwiftData
import DataThespian

enum DatabaseConstants {
    static let batchSize = 2_000
}

extension Container {

    var backgroundDatabase: Factory<Database> {
        self {
            let containerProvider = self.databaseContainerProvider()
            let mainContainer: ModelContainer
            do {
                mainContainer = try containerProvider.currentContainer()
            } catch {
                let databaseBackupFileManager = self.databaseBackupFileManager()
                do {
                    try retry(3, delay: 0.1) {
                        try databaseBackupFileManager.backupAndResetMainDatabase()
                    }
                    mainContainer = try containerProvider.currentContainer()
                } catch {
                    loggedFatalError("Database Error", error: error)
                }
            }

            return BackgroundDatabase(modelContainer: mainContainer) {
                let context = ModelContext($0)
                context.autosaveEnabled = false
                return context
            }
        }
        .singleton
    }
}

