//
//  DatabaseContainerManager.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 11.08.2025.
//

import SwiftData
import Foundation
import FactoryKit

extension Container {
    var databaseContainerProvider: Factory<DatabaseContainerProvider> {
        self { DatabaseContainerProviderImpl() }
    }
}

protocol DatabaseContainerProvider {
    func currentContainer() throws -> ModelContainer
    func container(for storeURL: URL) throws -> ModelContainer
}

final class DatabaseContainerProviderImpl: DatabaseContainerProvider {

    enum DatabaseError: Error {
        case noSchema
    }

    func currentContainer() throws -> ModelContainer {
        guard let currentSchema = DatabaseMigrationPlan.schemas.last else {
            throw DatabaseError.noSchema
        }

        let schema = Schema(versionedSchema: currentSchema)
        let container = try ModelContainer(for: schema, migrationPlan: DatabaseMigrationPlan.self)
        return container
    }

    func container(for storeURL: URL) throws -> ModelContainer {
        var schemas = DatabaseMigrationPlan.schemas
        let config = ModelConfiguration(url: storeURL)
        return try actualContainer(schemas: &schemas, config: config)
    }

    private func actualContainer(schemas: inout [VersionedSchema.Type], config: ModelConfiguration) throws -> ModelContainer {
        guard !schemas.isEmpty else {
            throw DatabaseError.noSchema
        }
        do {
            let schema = Schema(versionedSchema: schemas.removeLast())
            return try ModelContainer(for: schema, migrationPlan: DatabaseMigrationPlan.self, configurations: config)
        } catch {
            return try actualContainer(schemas: &schemas, config: config)
        }
    }
}

