import Foundation
import SwiftData

/// Протокол для обозначения объектов необходимых для импорта, быть аккуратнее со вложенными объектами
protocol MigratableModel: PersistentModel {
    associatedtype BackupModel: Codable & BackupRestorableModel
    func asMigrated() throws -> BackupModel
}

enum MigrationError: Error {
    case missingMainId
    case notMainSpectrumFolder
}

protocol BackupRestorableModel {
    static var typeId: String { get }

    associatedtype TargetModel: PersistentModel
    func asObject() -> TargetModel

    @discardableResult
    func insert(in context: ModelContext) throws -> TargetModel
}

extension BackupRestorableModel {

    static var typeId: String {
        "\(Self.self)"
    }

    @discardableResult
    func insert(in context: ModelContext) -> TargetModel {
        let model = asObject()
        context.insert(model)
        return model
    }

    func asObject() -> TargetModel {
        loggedFatalError("Override asObject() or insert(in:) fot type: \(Self.typeId)")
    }
}

