        guard FileManager.default.fileExists(atPath: url.path) else { return }

        let container = try databaseContainerProvider.currentContainer()
        let reader = try JSONReader<T.BackupModel>(url: url)
        defer { reader.close() }

        var batch: [T.BackupModel] = []
        batch.reserveCapacity(DatabaseConstants.batchSize)

        for item in reader {
            batch.append(item)
            if batch.count >= DatabaseConstants.batchSize {
                try saveBatch(batch, to: container)
                batch.removeAll(keepingCapacity: true)
                await Task.yield()
            }
        }
        if !batch.isEmpty {
            try saveBatch(batch, to: container)
        }
        try databaseBackupFileManager.removeModel(url)
    }

    private func saveBatch<M: BackupRestorableModel>(_ items: [M], to container: ModelContainer) throws {
        try autoreleasepool {
            let context = ModelContext(container)
            context.autosaveEnabled = false
            for item in items {
                _ = try? item.insert(in: context)
            }
            try context.save()
        }
    }
}
