import Foundation
import FactoryKit
import ZIPFoundation

final class DatabaseOptionsViewModel: ObservableObject {

    private enum ExportError: Error {
        case empty
    }

    enum ImportState {
        case notStarted
        case importing
        case failure
    }

    struct BackupFile {
        let url: URL
        let size: Int64
        let date: Date

        var megabytes: Double {
           Double(size) / (1024.0 * 1024.0)
        }
    }

    @Injected(\.databaseBackupFileManager) private var databaseBackupFileManager
    @Injected(\.databaseMigrationManager) private var databaseMigrationManager
    @Injected(\.toast) private var toast

    @Published var backupFile: BackupFile?
    @Published var importState: ImportState = .notStarted

    func checkDatabaseBackup() {
        guard let zipDatabase = try? databaseBackupFileManager.zipDB(),
              let size = try? FileManager.fileSizeForItem(at: zipDatabase),
              let date = try? FileManager.fileModificationDateTimeForItem(at: zipDatabase) else {
            backupFile = nil
            return
        }
        backupFile = .init(
            url: zipDatabase,
            size: size,
            date: date
        )
    }

    func exportMainDatabase() throws -> URL {
        do {
            return try databaseBackupFileManager.exportMainDB()
        } catch {
            Log.error(error)
            throw error
        }
    }

    func exportLogs() async throws -> URL {
        do {
            let logs = try LogStore.getLogs()
            guard !logs.isEmpty else {
                throw ExportError.empty
            }
            let encoder = JSONEncoder()
            encoder.outputFormatting = .prettyPrinted

            let jsonData = try encoder.encode(logs)
            let url = URL(fileURLWithPath: NSTemporaryDirectory(), isDirectory: true).appendingPathComponent("logs.json")
            try jsonData.write(to: url)
            return url
        } catch {
            Log.error(error)
            throw error
        }
    }

    func removeDatabaseBackup() {
        try? databaseBackupFileManager.removeDatabase(database: .zip)
        backupFile = nil
    }

    @MainActor
    func importDataBase(url: URL) async throws {
        importState = .importing
        do {
            let url = try databaseBackupFileManager.importDatabase(from: url)
            if await databaseMigrationManager.importDatabase(databaseUrl: url) {
                importState = .notStarted
                toast.show(style: .success, message: .Profile.databaseImported)
            } else {
                importState = .failure
            }
        } catch {
            Log.error(error)
            importState = .failure
        }
    }
}

