import Foundation
import ZIPFoundation
import FactoryKit
import SwiftData

typealias MigratablePersistentModel = MigratableModel & PersistentModel

extension Container {
    var databaseMigrationManager: Factory<DatabaseMigrationManager> {
        self { DatabaseMigrationManagerImpl() }
    }
}

protocol DatabaseMigrationManager {
    func migrateDatabaseIfNeeded() async
    func importDatabase(databaseUrl: URL) async -> Bool
}

final class DatabaseMigrationManagerImpl: DatabaseMigrationManager {

    @LazyInjected(\.backupCoordinator) private var backupCoordinator
    @LazyInjected(\.migration) private var migration
    @LazyInjected(\.databaseBackupFileManager) private var databaseBackupFileManager

    func migrateDatabaseIfNeeded() async {
        var migrationDataBaseUrl: URL?
        // Проверяем есть ли упавшая база
        if let databaseUrl = databaseBackupFileManager.brokenDatabase() {
            await migration.setState(.migrating)
            let success = await backupCoordinator.storeFromDatabase(from: databaseUrl)
            if !success {
                migrationDataBaseUrl = try? databaseBackupFileManager.zipDB()
            }
            // Удаление после экспорта, если успешно, то она больше не нужна, если нет, то база архиваируеся в zip
            removeDatabaseSafely(.backup)
        }

        await backupCoordinator.restore()

        let finalState: Migration.State = {
            if let url = migrationDataBaseUrl {
                return .failure(databaseURL: url)
            } else {
                return .ready
            }
        }()

        await migration.setState(finalState)
    }

    func importDatabase(databaseUrl: URL) async -> Bool {
        defer { removeDatabaseSafely(.import) }
        let success = await backupCoordinator.storeFromDatabase(from: databaseUrl)
        if success {
            do {
                try await backupCoordinator.clearAllObjectsDB()
                await backupCoordinator.restore()
            }
            catch {
                return false
            }
        }
        return success
    }

    private func removeDatabaseSafely(_ role: DatabaseBackupTarget) {
        do {
            try databaseBackupFileManager.removeDatabase(database: role)
        } catch {
            Log.error(error)
        }
    }
}

