import Foundation
import ZIPFoundation
import FactoryKit

extension Container {

    var databaseBackupFileManager: Factory<DatabaseBackupFileManager> {
        self { DatabaseBackupFileManagerImpl() }.shared
    }
}

enum DatabaseBackupTarget {
    case `import`
    case backup
    case zip
}

protocol DatabaseBackupFileManager {
    func backupAndResetMainDatabase() throws
    func brokenDatabase() -> URL?

    func zipDB() throws -> URL

    func removeModel(_ url: URL) throws
    func removeDatabase(database: DatabaseBackupTarget) throws

    func exportMainDB() throws -> URL
    func importDatabase(from url: URL) throws -> URL

    func modelURL(for modelName: String) throws -> URL
}

final class DatabaseBackupFileManagerImpl: DatabaseBackupFileManager {

    private enum BackupFileManagerError: Error {
        case backupFolderNotCreated
        case importFailed
    }

    private enum Consts {
        static let fileManager = FileManager.default
        static let applicationSupportDirectory = URL.applicationSupportDirectory
        static let temporaryDirectory = URL.temporaryDirectory

        static let targetFiles = [
            "default.store",
            "default.store-wal",
            "default.store-shm"
        ]

        static let backupFolderName = "Backup"
        static let databaseFolderName = "Database"
        static let modelsFolderName = "Models"
        static let backupFileName = "radiacode_backup.zip"

        static let importFolderName = "Import"
        static let exportFolderName = "Export"
        static let exportDatabaseFileName = "radiacode_database.zip"
    }

    private lazy var backupFolder: URL? = {
        do {
            let backupDirectory = Consts.applicationSupportDirectory.appendingPathComponent(Consts.backupFolderName)
            if !Consts.fileManager.fileExists(atPath: backupDirectory.path) {
                try Consts.fileManager.createDirectory(at: backupDirectory, withIntermediateDirectories: true, attributes: nil)
            }
            return backupDirectory
        } catch {
            Log.error(error)
            return nil
        }
    }()

    private var databaseFolder: URL? {
        guard let backupFolder else { return nil }
        return backupFolder.appendingPathComponent(Consts.databaseFolderName)
    }

    private var modelsFolder: URL? {
        guard let backupFolder else { return nil }
        return backupFolder.appendingPathComponent(Consts.modelsFolderName)
    }

    func backupAndResetMainDatabase() throws {
        guard let databaseFolder else {
            throw BackupFileManagerError.backupFolderNotCreated
        }

        if !Consts.fileManager.fileExists(atPath: databaseFolder.path) {
            try Consts.fileManager.createDirectory(at: databaseFolder, withIntermediateDirectories: true, attributes: nil)
        }

        for fileName in Consts.targetFiles {
            let sourceURL = Consts.applicationSupportDirectory.appendingPathComponent(fileName)
            guard Consts.fileManager.fileExists(atPath: sourceURL.path) else { continue }
            let destURL = databaseFolder.appendingPathComponent(fileName)
            try removeIfExists(destURL)
            try Consts.fileManager.copyItem(at: sourceURL, to: destURL)
            try removeIfExists(sourceURL)
        }
    }

    func brokenDatabase() -> URL? {
        guard let databaseFolder else { return nil }
        let storeURL = databaseFolder.appendingPathComponent(Consts.targetFiles[0])
        if Consts.fileManager.fileExists(atPath: storeURL.path) {
            return storeURL
        } else {
            return nil
        }
    }

    func zipDB() throws -> URL {
        guard let backupFolder, let databaseFolder else {
            throw BackupFileManagerError.backupFolderNotCreated
        }
        let archiveURL = backupFolder.appendingPathComponent(Consts.backupFileName)
        if !Consts.fileManager.fileExists(atPath: archiveURL.path) {
            try Consts.fileManager.zipItem(at: databaseFolder, to: archiveURL, shouldKeepParent: false)
        }
        return archiveURL
    }

    func removeDatabase(database: DatabaseBackupTarget) throws {
        let urlToDelete: URL
        switch database {
        case .backup:
            guard let databaseFolder else {
                throw BackupFileManagerError.backupFolderNotCreated
            }
            urlToDelete = databaseFolder
        case .import:
            urlToDelete = Consts.temporaryDirectory.appendingPathComponent(Consts.importFolderName)
        case .zip:
            guard let backupFolder else {
                throw BackupFileManagerError.backupFolderNotCreated
            }
            urlToDelete = backupFolder.appendingPathComponent(Consts.backupFileName)
        }
        try removeIfExists(urlToDelete)
    }

    func removeModel(_ url: URL) throws {
        try removeIfExists(url)
    }

    func exportMainDB() throws -> URL {
        let exportFolder = try createNewFolder(Consts.exportFolderName)
        let exportDatabaseFolder = try createNewFolder(Consts.databaseFolderName, directory: exportFolder)

        for fileName in Consts.targetFiles {
            let sourceURL = Consts.applicationSupportDirectory.appendingPathComponent(fileName)
            if Consts.fileManager.fileExists(atPath: sourceURL.path) {
                let destURL = exportDatabaseFolder.appendingPathComponent(fileName)
                try Consts.fileManager.copyItem(at: sourceURL, to: destURL)
            }
        }

        let archiveURL = exportFolder.appendingPathComponent(Consts.exportDatabaseFileName)
        try removeIfExists(archiveURL)
        try Consts.fileManager.zipItem(at: exportDatabaseFolder, to: archiveURL, shouldKeepParent: false)
        try removeIfExists(exportDatabaseFolder)
        return archiveURL
    }

    func importDatabase(from url: URL) throws -> URL {
        let importFolder = try createNewFolder(Consts.importFolderName)
        try Consts.fileManager.unzipItem(at: url, to: importFolder)
        let storeURL = importFolder.appendingPathComponent(Consts.targetFiles[0])
        if Consts.fileManager.fileExists(atPath: storeURL.path) {
            return storeURL
        } else {
            throw BackupFileManagerError.importFailed
        }
    }

    private func createNewFolder(_ folderName: String, directory: URL = Consts.temporaryDirectory) throws -> URL {
        let folder = directory.appendingPathComponent(folderName)
        try removeIfExists(folder)
        try Consts.fileManager.createDirectory(at: folder, withIntermediateDirectories: true, attributes: nil)
        return folder
    }

    func modelURL(for modelName: String) throws -> URL {
        guard let modelsFolder else {
            throw BackupFileManagerError.backupFolderNotCreated
        }
        if !Consts.fileManager.fileExists(atPath: modelsFolder.path) {
            try Consts.fileManager.createDirectory(at: modelsFolder, withIntermediateDirectories: true, attributes: nil)
        }

        return modelsFolder.appendingPathComponent("\(modelName).json")
    }

    private func removeIfExists(_ url: URL) throws {
        if Consts.fileManager.fileExists(atPath: url.path) {
            try Consts.fileManager.removeItem(at: url)
        }
    }
}

