//
//  DatabaseSqliteManger.swift
//  RadiaCode
//
//  Created by Matvey Kozin on 12.08.2025.
//

import Foundation
import ZIPFoundation
import FactoryKit
import SwiftData

typealias MigratablePersistentModel = MigratableModel & PersistentModel

extension Container {
    var databaseMigrationManager: Factory<DatabaseMigrationManager> {
        self { DatabaseMigrationManagerImpl() }
    }
}

protocol DatabaseMigrationManager {
    func migrateDatabaseIfNeeded() async
    func importDatabase(databaseUrl: URL) async -> Bool
}

final class DatabaseMigrationManagerImpl: DatabaseMigrationManager {

    @LazyInjected(\.backupCoordinator) private var backupCoordinator
    @LazyInjected(\.migration) private var migration
    @LazyInjected(\.databaseBackupFileManager) private var databaseBackupFileManager

    func migrateDatabaseIfNeeded() async {
        var migrationDataBaseUrl: URL?
        // Проверяем есть ли упавшая база
        if let databaseUrl = databaseBackupFileManager.brokenDatabase() {
            await migration.setState(.migrating)
            let success = await backupCoordinator.storeFromDatabase(from: databaseUrl)
            if !success {
                migrationDataBaseUrl = try? await databaseBackupFileManager.zipDBAsync()
            }
            // Удаление после экспорта, если успешно, то она больше не нужна, если нет, то база архиваируеся в zip
            removeDatabaseSafely(.backup)
        }

        await backupCoordinator.restore()

        let finalState: Migration.State = {
            if let url = migrationDataBaseUrl {
                return .failure(databaseURL: url)
            } else {
                return .ready
            }
        }()

        await migration.setState(finalState)
    }

    func importDatabase(databaseUrl: URL) async -> Bool {
        defer { removeDatabaseSafely(.import) }
        let success = await backupCoordinator.storeFromDatabase(from: databaseUrl)
        if success {
            do {
                try await backupCoordinator.clearAllObjectsDB()
                await backupCoordinator.restore()
            }
            catch {
                return false
            }
        }
        return success
    }

    private func removeDatabaseSafely(_ role: DatabaseBackupTarget) {
        do {
            try databaseBackupFileManager.removeDatabase(database: role)
        } catch {
            Log.error(error)
        }
    }
}

protocol DatabaseBackupFileManager {
    func backupAndResetMainDatabase() throws
    func brokenDatabase() -> URL?

    func zipDB() throws -> URL
    func zipDBAsync() async throws -> URL

    func removeModel(_ url: URL) throws
    func removeDatabase(database: DatabaseBackupTarget) throws

    func exportMainDB() throws -> URL
    func importDatabase(from url: URL) throws -> URL

    func modelURL(for modelName: String) throws -> URL
}

final class DatabaseBackupFileManagerImpl: DatabaseBackupFileManager {

    private enum BackupFileManagerError: Error {
        case backupFolderNotCreated
        case importFailed
    }

    private enum Consts {
        static let fileManager = FileManager.default
        static let applicationSupportDirectory = URL.applicationSupportDirectory
        static let temporaryDirectory = URL.temporaryDirectory

        static let targetFiles = [
            "default.store",
            "default.store-wal",
            "default.store-shm"
        ]

        static let backupFolderName = "Backup"
        static let databaseFolderName = "Database"
        static let modelsFolderName = "Models"
        static let backupFileName = "radiacode_backup.zip"

        static let importFolderName = "Import"
        static let exportFolderName = "Export"
        static let exportDatabaseFileName = "radiacode_database.zip"
    }

    private lazy var backupFolder: URL? = {
        do {
            let backupDirectory = Consts.applicationSupportDirectory.appendingPathComponent(Consts.backupFolderName)
            if !Consts.fileManager.fileExists(atPath: backupDirectory.path) {
                try Consts.fileManager.createDirectory(at: backupDirectory, withIntermediateDirectories: true, attributes: nil)
            }

